import React from 'react';
import { useNavigate } from 'react-router-dom';
import styles from './JobCard.module.css';

const JobCard = ({ job, isFull }) => {
    const navigate = useNavigate();

    return (
        <div className={styles.card} onClick={() => navigate(`/job/${job.id}`)}>
            <h3 className={styles.title}>{job.title}</h3>
            <p className={styles.company}>{job.company} • {job.location}</p>
            <p className={styles.salary}>💰 {job.salary}</p>

            {isFull && (
                <div className={styles.detailSection}>
                    <p className={styles.desc}>{job.desc}</p>
                    <button className={styles.applyBtn}>Lamar Sekarang</button>
                </div>
            )}
        </div>
    );
};

// PENTING: Tambahkan baris ini
export default JobCard;
